// Validation middleware factory
function validateBody(schema) {
  return (req, res, next) => {
    try {
      schema.parse({ body: req.body });
      next();
    } catch (err) {
      res.status(400).json({
        error: 'Validation failed',
        details: err.errors,
      });
    }
  };
}

